import React from "react";
import { useState } from "react";
import { useParams } from "react-router-dom";
import axios from "axios"
import { useEffect } from "react";
import { Link as LinkRouter } from "react-router-dom" 


function DetailsPages(){
    const{id}=useParams()
    const [card, setCard] = useState([])
    
    useEffect(() => {
        axios.get(`http://localhost:4000/api/cities/${id}`)
        .then(response => setCard(response.data.response))
    }, [])
    
    // useEffect(() => {
    //     setCard(cities.filter(data => data._id === id))
    // }, [])

    // let card = cities.filter(data => data._id === id)
    console.log(card);
    console.log(id);
    return(
        <div className="card-container">
            <div className="card">
                <div className="image">
                <img className="image-card" src= {card.city.image} alt="cities" />
                </div>
                <div>
                    <h2>{card.city.cityname}</h2>
                    <h3>{card.city.country}</h3>
                    <p>{card.city.description}</p>
                    <LinkRouter to={"/cities"}>
                        <button>Go Back!</button>
                    </LinkRouter>
                </div>
            </div>
        </div>
    );
}
export default DetailsPages
